121	func (r *Reconciler) updateImageInStatus(istiocsr *v1alpha1.IstioCSR, deployment *appsv1.Deployment) error {
122		for _, container := range deployment.Spec.Template.Spec.Containers {
123			if container.Name == istiocsrContainerName {
124				if istiocsr.Status.IstioCSRImage == container.Image {
125					return nil
126				}
127				istiocsr.Status.IstioCSRImage = container.Image
128			}
129		}
130		return r.updateStatus(r.ctx, istiocsr)
131	}
