137	func updateArgList(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR) {
138		istiocsrConfigs := istiocsr.Spec.IstioCSRConfig
139		// Default clusterID to "Kubernetes" if not provided.
140		clusterID := defaultClusterID
141		if istiocsrConfigs.Server != nil && istiocsrConfigs.Server.ClusterID != "" {
142			clusterID = istiocsrConfigs.Server.ClusterID
143		}
144		args := []string{
145			fmt.Sprintf("--log-level=%d", istiocsrConfigs.LogLevel),
146			fmt.Sprintf("--log-format=%s", istiocsrConfigs.LogFormat),
147			"--metrics-port=9402", "--readiness-probe-port=6060", "--readiness-probe-path=/readyz",
148			fmt.Sprintf("--certificate-namespace=%s", istiocsrConfigs.Istio.Namespace),
149			"--issuer-enabled=true", "--preserve-certificate-requests=false",
150			fmt.Sprintf("--issuer-name=%s", istiocsrConfigs.CertManager.IssuerRef.Name),
151			fmt.Sprintf("--issuer-kind=%s", istiocsrConfigs.CertManager.IssuerRef.Kind),
152			fmt.Sprintf("--issuer-group=%s", istiocsrConfigs.CertManager.IssuerRef.Group),
153			fmt.Sprintf("--root-ca-file=%s/%s", caVolumeMountPath, IstiocsrCAKeyName),
154			fmt.Sprintf("--serving-certificate-dns-names=cert-manager-istio-csr.%s.svc", istiocsr.GetNamespace()),
